import { NextResponse } from "next/server";
import fs from "fs";
import path from "path";

const filePath = path.join(process.cwd(), "data", "bays.json");

const readBaysFile = () => {
  try {
    if (!fs.existsSync(filePath)) {
      // Seed default workshop bays cleanly
      const defaultBays = [
        { id: "BAY-1", name: "Bay 1" },
        { id: "BAY-2", name: "Bay 2" },
        { id: "BAY-3", name: "Bay 3" },
        { id: "BAY-4", name: "Bay 4" }
      ];
      const dirPath = path.dirname(filePath);
      if (!fs.existsSync(dirPath)) fs.mkdirSync(dirPath, { recursive: true });
      fs.writeFileSync(filePath, JSON.stringify(defaultBays, null, 2), "utf-8");
      return defaultBays;
    }
    return JSON.parse(fs.readFileSync(filePath, "utf-8"));
  } catch (error) {
    return [];
  }
};

const writeBaysFile = (data: any) => {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
};

export async function GET() {
  return NextResponse.json(readBaysFile());
}

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { name } = body;

    if (!name) {
      return NextResponse.json({ error: "Missing bay identification name." }, { status: 400 });
    }

    const currentBays = readBaysFile();
    const nextId = `BAY-${currentBays.length + 1}`;

    const newBay = { id: nextId, name };
    currentBays.push(newBay);
    writeBaysFile(currentBays);

    return NextResponse.json({ success: true, data: newBay }, { status: 201 });
  } catch (error) {
    return NextResponse.json({ error: "Internal Error saving workshop bay asset." }, { status: 500 });
  }
}